def solve(grid):
    import copy
    grid = [list(row) for row in grid]
    rows, cols = len(grid), len(grid[0])
    out = copy.deepcopy(grid)

    legend = {}
    for c in range(cols):
        r = 0
        if grid[0][c] == 0:
            continue
        val = grid[0][c]
        count = 0
        while r < rows and grid[r][c] == val:
            count += 1
            r += 1
        legend[val] = count

    sticks_by_bookend = {}
    for c in range(cols):
        col = [grid[r][c] for r in range(rows)]
        seg_start = None
        for r in range(rows + 1):
            v = col[r] if r < rows else 0
            if v != 0:
                if seg_start is None:
                    seg_start = r
            else:
                if seg_start is not None:
                    seg = col[seg_start:r]
                    if len(seg) >= 3 and seg[0] == seg[-1]:
                        bk = seg[0]
                        has_fill = any(v != bk for v in seg)
                        if has_fill:
                            if bk not in sticks_by_bookend:
                                sticks_by_bookend[bk] = []
                            sticks_by_bookend[bk].append((c, seg_start, r - 1))
                    seg_start = None

    for bk, sticks in sticks_by_bookend.items():
        if bk not in legend:
            continue
        n = legend[bk]
        sticks_sorted = sorted(sticks, key=lambda s: s[1])
        if n <= len(sticks_sorted):
            target = sticks_sorted[n - 1]
            col_idx, s_start, s_end = target
            for r in range(s_start, s_end + 1):
                out[r][col_idx] = bk

    return out

