                    if 0 <= mr < rows and g[mr][c] != 0:
                        g[r][c] = g[mr][c]
                        changed = True
                        continue
                    mc = K - c
                    if 0 <= mc < cols and g[r][mc] != 0:
                        g[r][c] = g[r][mc]
