def solve(grid):
    from collections import deque
    grid = [list(row) for row in grid]
    rows, cols = len(grid), len(grid[0])
    start = None
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 6:
                start = (r, c)
    visited = set()
    queue = deque([start])
    visited.add(start)
    while queue:
        r, c = queue.popleft()
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < rows and 0 <= nc < cols and (nr,nc) not in visited:
                if grid[nr][nc] != 1:
                    visited.add((nr,nc))
                    queue.append((nr,nc))
    one_visited = set()
    ones_to_keep = set()
    wall_ones = set()
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 1 and (r,c) not in one_visited:
                comp = []
                q = deque([(r,c)])
                one_visited.add((r,c))
                adj_flood = False
                adj_outside = False
                while q:
                    cr, cc = q.popleft()
                    comp.append((cr, cc))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if nr < 0 or nr >= rows or nc < 0 or nc >= cols:
                            adj_outside = True
                        elif grid[nr][nc] == 1 and (nr,nc) not in one_visited:
                            one_visited.add((nr,nc))
                            q.append((nr,nc))
                        elif (nr,nc) in visited:
                            adj_flood = True
                        elif grid[nr][nc] != 1:
                            adj_outside = True
                if adj_flood:
                    for cell in comp:
                        ones_to_keep.add(cell)
                    if adj_outside:
                        for cell in comp:
                            wall_ones.add(cell)
    out = [[8]*cols for _ in range(rows)]
    out[start[0]][start[1]] = 6
    for r, c in ones_to_keep:
        out[r][c] = 1
    for r, c in visited:
        if grid[r][c] == 6:
            continue
        is_border = False
        if r == 0 or r == rows-1 or c == 0 or c == cols-1:
            is_border = True
        if not is_border:
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0: continue
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < rows and 0 <= nc < cols and (nr,nc) in wall_ones:
                        is_border = True
                        break
                if is_border: break
        if not is_border:
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 6:
                    is_border = True
                    break
        if is_border:
            out[r][c] = 7
    return out
